ws(){return A.a([new A.je(1,"A Trilha","O Deus Criador\ne eterno","A Trilha \xe9 a base para entender sobre Criacionismo. A primeira li\xe7\xe3o trata da exist\xeancia de Deus, e \xe9 a mais importante porque nada faz sentido se n\xe3o assumirmos que existe um Deus e que Ele \xe9 eterno e criador. As li\xe7\xf5es seguintes desse m\xf3dulo tratam do que Deus criou e de como Ele criou. H\xe1 pequenas experi\xeancias cient\xedficas e dados que ajudar\xe3o as crian\xe7as a tomarem uma posi\xe7\xe3o firme frente ao evolucionismo pregado nas escolas. A inten\xe7\xe3o \xe9 que elas assumam essa verdade para elas pela f\xe9, por\xe9m tamb\xe9m com l\xf3gica e racionalidade.","assets/image/capas/trilha.png"),new A.je(2,"O Mergulho","O Pecado","O Mergulho \xe9 a base para o arrependimento e mudan\xe7a de vida. Mostra a condi\xe7\xe3o do homem pecador e distante de Deus. Inicia com informa\xe7\xf5es sobre o inimigo de Deus e o pecado de Ad\xe3o e Eva, segue com as consequ\xeancias do pecado, a promessa de um salvador, a provis\xe3o e a expuls\xe3o do jardim.","assets/image/capas/mergulho.jpg"),new A.je(3,"O Santu\xe1rio","A Palavra de Deus","O Santu\xe1rio \xe9 uma nova aventura. Neste terceiro m\xf3dulo, voc\xeas aprender\xe3o juntos sobre a Palavra de Deus e como ela \xe9 digna de toda confian\xe7a. T\xe3o digna que devemos construir o nossa vida como santu\xe1rio de Deus fundamentado nela.","assets/image/capas/santuario.jpg"),new A.je(4,"O Arco","A Salva\xe7\xe3o em Jesus","O Arco far\xe1 voc\xeas lembrarem o pacto que Deus fez com o homem de n\xe3o o destruir mais atrav\xe9s da \xe1gua, por\xe9m a condena\xe7\xe3o de Deus para com o pecado continuou e a simbologia do arco, que usa a mesma palavra no hebraico para a arma arco, prop\xf5e que Deus mostrou ao homem que seu alvo para condena\xe7\xe3o seria Ele pr\xf3prio. O pr\xf3prio Deus entregaria sua vida atrav\xe9s de seu filho Jesus para pagar a condena\xe7\xe3o do pecado.","assets/image/capas/capa-arco.png"),new A.je(5,"A Esta\xe7\xe3o Final","A Eternidade com\nCristo","A Esta\xe7\xe3o Final voc\xea e suas crian\xe7as v\xe3o completar a vis\xe3o cronol\xf3gica da B\xedblia observando a hist\xf3ria, desde a igreja primitiva at\xe9 o dia em que essa mesma igreja ir\xe1 viver eternamente com seu Deus.","assets/image/capas/estacao-final.jpg")],t.cF)},
